import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

type FilingStatus = "single" | "joint" | "separate" | "head";
const FAQS = [
  { q: "How do US federal tax brackets work?", a: "US federal brackets are marginal. Each tax rate applies only to income within that bracket, not to your entire income." },
  { q: "What is the difference between effective and marginal tax rate?", a: "Marginal rate is the rate on your next dollar of taxable income. Effective rate is total tax divided by gross income." },
  { q: "What is the standard deduction?", a: "The standard deduction is a fixed amount that reduces taxable income before federal tax is calculated." },
  { q: "How does filing status affect your taxes?", a: "Filing status changes your standard deduction and bracket thresholds, which can change tax owed and take-home pay." },
  { q: "What are tax credits vs tax deductions?", a: "Deductions reduce taxable income. Credits reduce tax owed dollar for dollar." },
];
const BRACKETS_SINGLE = [[0, 11600, .10], [11600, 47150, .12], [47150, 100525, .22], [100525, 191950, .24], [191950, 243725, .32], [243725, 609350, .35], [609350, Infinity, .37]];
const STANDARD: Record<FilingStatus, number> = { single: 14600, joint: 29200, separate: 14600, head: 21900 };
const MULTIPLIER: Record<FilingStatus, number> = { single: 1, joint: 2, separate: 1, head: 1.45 };
const money = (value: number, digits = 0) => formatCurrencyValue(value, { maximumFractionDigits: digits });
function bracketsFor(status: FilingStatus) { return BRACKETS_SINGLE.map(([min, max, rate]) => [min * MULTIPLIER[status], max === Infinity ? Infinity : max * MULTIPLIER[status], rate]); }
function taxFor(taxable: number, brackets: number[][]) { return brackets.reduce((sum, [min, max, rate]) => taxable > min ? sum + (Math.min(taxable, max) - min) * rate : sum, 0); }
function bracketBreakdown(taxable: number, brackets: number[][]) { return brackets.map(([min, max, rate]) => ({ rate, min, max, tax: taxable > min ? (Math.min(taxable, max) - min) * rate : 0 })).filter((row) => row.tax > 0); }

export default function IncomeTaxCalculator() {
  useCurrencyVersion();
  const [income, setIncome] = useState(85000);
  const [status, setStatus] = useState<FilingStatus>("single");
  const [state, setState] = useState("CA");
  const [dependents, setDependents] = useState(0);
  const brackets = useMemo(() => bracketsFor(status), [status]);
  const taxable = Math.max(0, income - STANDARD[status] - dependents * 2000);
  const tax = taxFor(taxable, brackets);
  const effective = income > 0 ? tax / income * 100 : 0;
  const marginal = (brackets.find(([, max]) => taxable <= max)?.[2] || 0) * 100;
  const takeHome = income - tax;
  const breakdown = bracketBreakdown(taxable, brackets);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  return (
    <>
      <SEOHead title="Free Income Tax Calculator Online - Calculate Your Federal Tax and Take-Home Pay Instantly | CalcHive" description="Free online income tax calculator. Calculate federal income tax owed, effective tax rate, marginal rate and take-home pay for any income and filing status instantly. 100% free, no signup required." canonical="/income-tax-calculator" keywords="free income tax calculator, federal tax calculator free online, income tax estimator free, calculate take home pay free, tax bracket calculator free online" category="Financial Calculators" breadcrumbName="Free Income Tax Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Income Tax Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate federal income tax, marginal tax rate, effective tax rate, and take-home pay by filing status.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Annual gross income</label><input type="number" value={income} onChange={(e) => setIncome(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Filing status</label><select value={status} onChange={(e) => setStatus(e.target.value as FilingStatus)} className={inputClass}><option value="single">Single</option><option value="joint">Married filing jointly</option><option value="separate">Married filing separately</option><option value="head">Head of household</option></select></div><div><label className="text-sm font-semibold text-foreground block mb-2">State</label><input value={state} onChange={(e) => setState(e.target.value)} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Dependents</label><input type="number" value={dependents} onChange={(e) => setDependents(Number(e.target.value))} className={inputClass} /></div></div><motion.div key={`${income}-${status}-${state}-${dependents}`} initial={{ opacity: .7, y: 4 }} animate={{ opacity: 1, y: 0 }}><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Federal Tax Owed</p><p className="text-5xl sm:text-6xl font-black text-white" data-testid="result-tax">{money(tax)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">{[["Effective rate", `${effective.toFixed(1)}%`], ["Marginal rate", `${marginal.toFixed(0)}%`], ["Take-home pay", money(takeHome)]].map(([label, value]) => <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">{label}</p><p className="text-lg font-extrabold text-foreground">{value}</p></div>)}</div></motion.div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Your Federal Income Tax for Free</h2><p className="text-muted-foreground leading-relaxed">Subtract the standard deduction and dependent adjustment, then apply each marginal bracket to taxable income.</p><h2 className="text-2xl font-bold text-foreground">How Tax Brackets and Marginal Rates Work</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Federal Income Tax Brackets 2024 - Single Filer</caption><thead className="bg-muted/60"><tr>{["Tax Rate", "Income Range", "Tax on This Bracket"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{BRACKETS_SINGLE.map(([min, max, rate]) => <tr key={rate} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-bold text-sky-600 dark:text-sky-400">{(rate * 100).toFixed(0)}%</td><td className="py-2.5 px-3">{max === Infinity ? `Over ${money(min)}` : `${money(min)} to ${money(max)}`}</td><td className="py-2.5 px-3">{max === Infinity ? "37% above threshold" : money((max - min) * rate)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Tax Estimator for Every Filing Status</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Your Tax Bracket Breakdown</caption><thead className="bg-muted/60"><tr>{["Rate", "Bracket Range", "Tax"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{breakdown.map((row) => <tr key={`${row.rate}-${row.min}`}><td className="py-2.5 px-3">{(row.rate * 100).toFixed(0)}%</td><td className="py-2.5 px-3">{money(row.min)} to {row.max === Infinity ? "above" : money(row.max)}</td><td className="py-2.5 px-3">{money(row.tax)}</td></tr>)}</tbody></table></div></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/income-tax-calculator" headingLevel="h3" /></main>
    </>
  );
}


